namespace TodoApi;public class TaskService(TodoDb db){const int WipLimit=5;static readonly Dictionary<TaskState,TaskState[]> Allowed=new(){[TaskState.Todo]=[TaskState.InProgress,TaskState.Archived],[TaskState.InProgress]=[TaskState.Blocked,TaskState.Done,TaskState.Todo],[TaskState.Blocked]=[TaskState.InProgress,TaskState.Archived],[TaskState.Done]=[TaskState.Archived,TaskState.InProgress],[TaskState.Archived]=[],};public async Task<TodoTask> TransitionAsync(int id,TaskState to,CT ct){var task=await db.Tasks.inc(t=>t.Subtasks).w(t=>t.Id==id).one(ct)??throw new KNF();if(task.Status==to)return task;if(!Allowed.TryGetValue(task.Status,out var next)||!next.Contains(to))throw new DomainException($"Cannot move a task from {task.Status} to {to}.");if(to==TaskState.Done&&task.Subtasks.Any(s=>s.Status is not(TaskState.Done or TaskState.Archived)))throw new DomainException("Cannot complete a task while it has open subtasks.");if(to==TaskState.InProgress)await GuardWipAsync(task.AssigneeId,id,ct);task.Status=to;if(to==TaskState.Done){task.CompletedAt=DateTime.UtcNow;if(task.RecurrenceDays is int days)db.Tasks.Add(NextOccurrence(task,days));}await db.save(ct);return task;}public async Task<TodoTask> AssignAsync(int id,int? assigneeId,CT ct){var task=await db.Tasks.id(id)??throw new KNF();if(task.Status==TaskState.InProgress)await GuardWipAsync(assigneeId,id,ct);task.AssigneeId=assigneeId;await db.save(ct);return task;}async Task GuardWipAsync(int? assigneeId,int excludeId,CT ct){if(assigneeId is not int who)return;var wip=await db.Tasks.w(t=>t.AssigneeId==who&&t.Status==TaskState.InProgress&&t.Id!=excludeId).cnt(ct);if(wip>=WipLimit)throw new DomainException($"Assignee {who} is at the WIP limit ({WipLimit}).");}static TodoTask NextOccurrence(TodoTask t,int days)=>new(){ListId=t.ListId,Title=t.Title,Notes=t.Notes,Priority=t.Priority,AssigneeId=t.AssigneeId,RecurrenceDays=t.RecurrenceDays,DueAt=(t.DueAt??DateTime.UtcNow).AddDays(days),Status=TaskState.Todo,CreatedAt=DateTime.UtcNow};}